16	// ADR-022 §Worker-server interface (rev 5). Workers are autonomous; the
17	// server's view of who's working is derived from best-effort event reports.
18	// This file implements the three ingestion endpoints:
19	//
20	//   POST /api/workers/register        — issue a worker_id for an identity envelope
21	//   POST /api/workers/{id}/event      — append a worker-emitted event
22	//   POST /api/workers/{id}/backfill   — replay buffered events after reconnect
23	//
24	// In-memory derived view backed by an append-only JSONL log at
25	// .ddx/server/worker-events.jsonl under the server's WorkingDir. Both the
26	// registry and the log are best-effort: if the server crashes the workers
27	// keep operating and re-register on next probe.
28	
29	const workerIngestMaxBodyBytes = 1 << 20 // 1 MiB cap on register/event/backfill payloads.
30	
31	// errUnknownWorker signals that a worker_id is not present in the in-memory
32	// registry. Surfaced as 410 Gone so the worker re-registers within the same
33	// probe cycle (ADR-022 §Probe + freshness state model).
34	var errUnknownWorker = errors.New("unknown_worker")
35	
36	// workerIdentity is the thin envelope POSTed on /api/workers/register.
37	type workerIdentity struct {
38		ProjectRoot  string    `json:"project_root"`
39		Harness      string    `json:"harness"`
40		Model        string    `json:"model,omitempty"`
41		ExecutorPID  int       `json:"executor_pid"`
42		ExecutorHost string    `json:"executor_host"`
43		StartedAt    time.Time `json:"started_at"`
44	}
45	
46	// workerEvent mirrors a single bead-event the worker would write to its
47	// local event log. The wire payload is intentionally minimal — the bead's
48	// local log remains the authoritative copy.
49	type workerEvent struct {
50		BeadID    string          `json:"bead_id"`
51		AttemptID string          `json:"attempt_id"`
52		Kind      string          `json:"kind"`
53		Body      json.RawMessage `json:"body,omitempty"`
54	}
55	
56	// workerBackfillRequest carries the worker's NotConnected ring buffer.
57	// dropped=true means oldest events were silently dropped at the worker
58	// (rev 5: HadDroppedBackfill flag surfaces "consult bead-local logs").
59	type workerBackfillRequest struct {
60		Events  []workerEvent `json:"events"`
61		Dropped bool          `json:"dropped,omitempty"`
62	}
63	
64	// workerRecord is the per-worker derived state the server holds in memory.
65	type workerRecord struct {
66		WorkerID            string         `json:"worker_id"`
67		Identity            workerIdentity `json:"identity"`
68		RegisteredAt        time.Time      `json:"registered_at"`
69		LastEventAt         time.Time      `json:"last_event_at"`
70		MirrorFailuresCount int            `json:"mirror_failures_count"`
71		HadDroppedBackfill  bool           `json:"had_dropped_backfill"`
72	}
73	
74	// workerIngestRegistry holds the in-memory derived view + owns the
75	// append-only event log. All exported methods are safe for concurrent use.
76	type workerIngestRegistry struct {
77		mu       sync.Mutex
78		workers  map[string]*workerRecord
79		logPath  string
80		logFile  *os.File
81		openOnce sync.Once
82		openErr  error
83	}
84	
85	func newWorkerIngestRegistry(workingDir string) *workerIngestRegistry {
86		return &workerIngestRegistry{
87			workers: make(map[string]*workerRecord),
88			logPath: filepath.Join(workingDir, ".ddx", "server", "worker-events.jsonl"),
89		}
90	}
91	
92	// register stores a new worker record and returns the issued worker_id.
93	func (r *workerIngestRegistry) register(id workerIdentity) *workerRecord {
94		now := time.Now().UTC()
95		rec := &workerRecord{
96			WorkerID:     newWorkerID(),
97			Identity:     id,
98			RegisteredAt: now,
99			LastEventAt:  now,
100		}
101		r.mu.Lock()
102		r.workers[rec.WorkerID] = rec
103		r.mu.Unlock()
104		return rec
105	}
106	
107	// recordEvent appends ev to the JSONL log and refreshes the worker's
108	// last_event_at timestamp. Returns errUnknownWorker if workerID is not
109	// registered.
110	func (r *workerIngestRegistry) recordEvent(workerID string, ev workerEvent) error {
111		r.mu.Lock()
112		rec, ok := r.workers[workerID]
113		if !ok {
114			r.mu.Unlock()
115			return errUnknownWorker
116		}
117		rec.LastEventAt = time.Now().UTC()
118		r.mu.Unlock()
119		return r.append(workerID, ev)
120	}
121	
122	// recordBackfill appends every event in the buffer; flips
123	// HadDroppedBackfill when the worker reports dropped overflow.
124	func (r *workerIngestRegistry) recordBackfill(workerID string, req workerBackfillRequest) error {
125		r.mu.Lock()
126		rec, ok := r.workers[workerID]
127		if !ok {
128			r.mu.Unlock()
129			return errUnknownWorker
130		}
131		if req.Dropped {
132			rec.HadDroppedBackfill = true
133		}
134		if len(req.Events) > 0 {
135			rec.LastEventAt = time.Now().UTC()
136		}
137		r.mu.Unlock()
138		for _, ev := range req.Events {
139			if err := r.append(workerID, ev); err != nil {
140				return err
141			}
142		}
143		return nil
144	}
145	
146	// snapshot returns a copy of the registry for read-only inspection (tests
147	// and future GraphQL consumers). The returned slice is a stable copy; the
148	// records themselves are pointers into the registry and must be treated
149	// as read-only.
150	func (r *workerIngestRegistry) snapshot() []*workerRecord {
151		r.mu.Lock()
152		defer r.mu.Unlock()
153		out := make([]*workerRecord, 0, len(r.workers))
154		for _, rec := range r.workers {
155			copy := *rec
156			out = append(out, &copy)
157		}
158		return out
159	}
