231	// --- HTTP handlers -----------------------------------------------------
232	
233	func (s *Server) handleWorkerRegister(w http.ResponseWriter, r *http.Request) {
234		var id workerIdentity
235		if err := decodeWorkerIngestBody(r, &id); err != nil {
236			writeJSON(w, http.StatusBadRequest, map[string]string{"error": err.Error()})
237			return
238		}
239		if id.ProjectRoot == "" {
240			writeJSON(w, http.StatusBadRequest, map[string]string{"error": "project_root required"})
241			return
242		}
243		rec := s.workerIngest.register(id)
244		writeJSON(w, http.StatusOK, map[string]string{"worker_id": rec.WorkerID})
245	}
246	
247	func (s *Server) handleWorkerEvent(w http.ResponseWriter, r *http.Request) {
248		workerID := r.PathValue("id")
249		if workerID == "" {
250			writeJSON(w, http.StatusBadRequest, map[string]string{"error": "worker id required"})
251			return
252		}
253		var ev workerEvent
254		if err := decodeWorkerIngestBody(r, &ev); err != nil {
255			writeJSON(w, http.StatusBadRequest, map[string]string{"error": err.Error()})
256			return
257		}
258		if ev.Kind == "" {
259			writeJSON(w, http.StatusBadRequest, map[string]string{"error": "kind required"})
260			return
261		}
262		if err := s.workerIngest.recordEvent(workerID, ev); err != nil {
263			if errors.Is(err, errUnknownWorker) {
264				writeJSON(w, http.StatusGone, map[string]string{"error": "unknown_worker"})
265				return
266			}
267			writeJSON(w, http.StatusInternalServerError, map[string]string{"error": err.Error()})
268			return
269		}
270		w.WriteHeader(http.StatusNoContent)
271	}
272	
273	func (s *Server) handleWorkerBackfill(w http.ResponseWriter, r *http.Request) {
274		workerID := r.PathValue("id")
275		if workerID == "" {
276			writeJSON(w, http.StatusBadRequest, map[string]string{"error": "worker id required"})
277			return
278		}
279		var req workerBackfillRequest
280		if err := decodeWorkerIngestBody(r, &req); err != nil {
281			writeJSON(w, http.StatusBadRequest, map[string]string{"error": err.Error()})
282			return
283		}
284		if err := s.workerIngest.recordBackfill(workerID, req); err != nil {
285			if errors.Is(err, errUnknownWorker) {
286				writeJSON(w, http.StatusGone, map[string]string{"error": "unknown_worker"})
287				return
288			}
289			writeJSON(w, http.StatusInternalServerError, map[string]string{"error": err.Error()})
290			return
291		}
292		w.WriteHeader(http.StatusNoContent)
293	}
294	
295	func decodeWorkerIngestBody(r *http.Request, v any) error {
296		r.Body = http.MaxBytesReader(nil, r.Body, workerIngestMaxBodyBytes)
297		if err := json.NewDecoder(r.Body).Decode(v); err != nil {
298			return fmt.Errorf("invalid request body: %w", err)
299		}
300		return nil
301	}
