303	// freshnessState classifies a worker by recency of its last_event_at against
304	// the probe interval (ADR-022 rev 5: connected ≤2× probe; stale ≤10× probe;
305	// disconnected otherwise). Probe default is 30s, hard-coded here because the
306	// per-worker poll_interval is not part of the rev-5 register payload.
307	func freshnessState(rec *workerRecord, now time.Time) string {
308		const probeInterval = 30 * time.Second
309		age := now.Sub(rec.LastEventAt)
310		switch {
311		case age <= 2*probeInterval:
312			return "connected"
313		case age <= 10*probeInterval:
314			return "stale"
315		default:
316			return "disconnected"
317		}
318	}
