13	// addrFallbackWarnWriter receives the warning emitted when ReadServerAddr
14	// detects a stale server.addr (recorded pid is not alive). Tests swap this
15	// for a buffer to assert the warning is produced.
16	var addrFallbackWarnWriter io.Writer = os.Stderr
17	
18	// SingletonLockError is returned by acquireSingletonLock when another live
19	// ddx-server already holds the per-machine lock.
20	type SingletonLockError struct {
21		PID  int
22		Addr string
23	}
24	
25	func (e *SingletonLockError) Error() string {
26		addr := e.Addr
27		if addr == "" {
28			addr = "unknown"
29		}
30		return fmt.Sprintf("ddx server already running, pid=%d, addr=%s; only one ddx server per machine", e.PID, addr)
31	}
