33	// acquireSingletonLock takes a per-machine lock so at most one ddx-server runs
34	// on a given host. The lock is a directory at <serverAddrDir>/server.lock
35	// containing a pid file. If the directory exists with an alive pid, an error
36	// is returned. If the pid is dead, the lock is broken and re-acquired (this
37	// covers crashes that left a stale lock). The returned release function
38	// removes the lock; callers should defer it.
39	func acquireSingletonLock() (func(), error) {
40		dir := serverAddrDir()
41		if err := os.MkdirAll(dir, 0700); err != nil {
42			return nil, fmt.Errorf("server: lock dir: %w", err)
43		}
44		lockDir := filepath.Join(dir, "server.lock")
45		pidPath := filepath.Join(lockDir, "pid")
46	
47		for attempt := 0; attempt < 2; attempt++ {
48			if err := os.Mkdir(lockDir, 0700); err == nil {
49				if err := os.WriteFile(pidPath, []byte(strconv.Itoa(os.Getpid())), 0600); err != nil {
50					_ = os.RemoveAll(lockDir)
51					return nil, fmt.Errorf("server: write lock pid: %w", err)
52				}
53				release := func() {
54					data, _ := os.ReadFile(pidPath)
55					if pid, err := strconv.Atoi(strings.TrimSpace(string(data))); err == nil && pid == os.Getpid() {
56						_ = os.RemoveAll(lockDir)
57					}
58				}
59				return release, nil
60			}
61	
62			pidData, _ := os.ReadFile(pidPath)
63			pid, perr := strconv.Atoi(strings.TrimSpace(string(pidData)))
64			if perr == nil && pid > 0 && processAlive(pid) {
65				return nil, &SingletonLockError{PID: pid, Addr: ReadRawServerAddr()}
66			}
67	
68			// Stale lock (dead pid, missing pid file, or our own pid leftover).
69			if err := os.RemoveAll(lockDir); err != nil {
70				return nil, fmt.Errorf("server: break stale lock: %w", err)
71			}
72		}
73		return nil, fmt.Errorf("server: could not acquire singleton lock at %s", lockDir)
74	}
