363	// serverAddrDir returns the user-level directory for the server address file.
364	// Follows XDG_DATA_HOME if set, else ~/.local/share/ddx.
365	func serverAddrDir() string {
366		if xdg := os.Getenv("XDG_DATA_HOME"); xdg != "" {
367			return filepath.Join(xdg, "ddx")
368		}
369		home, err := os.UserHomeDir()
370		if err != nil {
371			return filepath.Join("/tmp", "ddx")
372		}
373		return filepath.Join(home, ".local", "share", "ddx")
374	}
