376	// ReadServerAddr reads the last-written server address from the user-level
377	// addr file. Returns "" if none is present, or if the recorded pid is not
378	// alive (in which case a warning is emitted and the stale file is best-effort
379	// cleared so callers fall back to the default URL).
380	func ReadServerAddr() string {
381		type addrFile struct {
382			URL string `json:"url"`
383			PID int    `json:"pid"`
384		}
385		path := filepath.Join(serverAddrDir(), "server.addr")
386		data, err := os.ReadFile(path)
387		if err != nil {
388			return ""
389		}
390		var af addrFile
391		if err := json.Unmarshal(data, &af); err != nil {
392			return ""
393		}
394		if af.PID > 0 && !processAlive(af.PID) {
395			fmt.Fprintf(addrFallbackWarnWriter,
396				"warning: server.addr points to a dead pid %d; falling back to default 127.0.0.1:7743\n",
397				af.PID)
398			_ = os.Remove(path)
399			return ""
400		}
401		return af.URL
402	}
