558	// requireTrusted wraps a handler so non-loopback, non-tailnet requests are
559	// rejected with 403 before the handler executes.
560	func requireTrusted(next http.HandlerFunc) http.HandlerFunc {
561		return func(w http.ResponseWriter, r *http.Request) {
562			if !isTrusted(r) {
563				writeJSON(w, http.StatusForbidden, map[string]string{"error": "forbidden: trusted connection required"})
564				return
565			}
566			next(w, r)
567		}
568	}
