37	// readWorkerEventsLog returns each line of .ddx/server/worker-events.jsonl as
38	// a parsed loggedEvent. Returns an empty slice when the file does not exist.
39	func readWorkerEventsLog(t *testing.T, workingDir string) []loggedEvent {
40		t.Helper()
41		path := filepath.Join(workingDir, ".ddx", "server", "worker-events.jsonl")
42		f, err := os.Open(path)
43		if err != nil {
44			if os.IsNotExist(err) {
45				return nil
46			}
47			t.Fatalf("open events log: %v", err)
48		}
49		defer f.Close()
50		var out []loggedEvent
51		sc := bufio.NewScanner(f)
52		for sc.Scan() {
53			var ev loggedEvent
54			if err := json.Unmarshal(sc.Bytes(), &ev); err != nil {
55				t.Fatalf("decode log line %q: %v", sc.Text(), err)
56			}
57			out = append(out, ev)
58		}
59		if err := sc.Err(); err != nil {
60			t.Fatalf("scan log: %v", err)
61		}
62		return out
63	}
