65	// registerWorker POSTs a register payload and returns the issued worker_id.
66	func registerWorker(t *testing.T, srv *Server, projectRoot string) string {
67		t.Helper()
68		w := postLoopback(t, srv, "/api/workers/register", workerIdentity{
69			ProjectRoot:  projectRoot,
70			Harness:      "claude",
71			ExecutorPID:  4242,
72			ExecutorHost: "host.local",
73		})
74		if w.Code != http.StatusOK {
75			t.Fatalf("register: status=%d body=%s", w.Code, w.Body.String())
76		}
77		var resp struct {
78			WorkerID string `json:"worker_id"`
79		}
80		if err := json.Unmarshal(w.Body.Bytes(), &resp); err != nil {
81			t.Fatalf("decode register response: %v", err)
82		}
83		if resp.WorkerID == "" {
84			t.Fatal("register: empty worker_id")
85		}
86		if !strings.HasPrefix(resp.WorkerID, "wkr-") {
87			t.Errorf("worker_id %q missing wkr- prefix", resp.WorkerID)
88		}
89		return resp.WorkerID
90	}
