// Package workerprobe implements the ADR-022 rev 5 worker-side server probe
// goroutine + best-effort event mirror.
//
// The worker is autonomous: it executes beads regardless of whether a server
// is reachable. In parallel, this Probe periodically checks
// ~/.local/share/ddx/server.addr (XDG-compliant) for a reachable server. On
// NotConnected→Connected transition the probe POSTs a thin identity envelope
// to /api/workers/register, stashes the issued worker_id, and starts mirroring
// per-attempt events to /api/workers/{id}/event best-effort. Buffered events
// from the NotConnected period are flushed via /api/workers/{id}/backfill.
//
// All HTTP calls are best-effort: failures are logged and ignored. The bead's
// local event log is the authoritative copy; the server-side derived view is
// observability only.
package workerprobe

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"math/rand"
	"net/http"
	"sync"
	"time"
)

// DefaultBufferCap is the ring-buffer size for events emitted while
// NotConnected. Per ADR-022 rev 5: 200 events; oldest dropped silently;
// HadDroppedBackfill flag on overflow.
const DefaultBufferCap = 200

// DefaultBaseInterval is the steady-state probe cadence (30s ± jitter).
const DefaultBaseInterval = 30 * time.Second

// DefaultMaxInterval caps the probe cadence under backoff (5min).
const DefaultMaxInterval = 5 * time.Minute

// DefaultJitterPct controls ± jitter applied to BaseInterval.
const DefaultJitterPct = 0.20

// DefaultBackoffThreshold is the consecutive-failure count after which the
// probe enters backoff (interval lengthens to MaxInterval).
const DefaultBackoffThreshold = 5

// Identity is the thin envelope POSTed on /api/workers/register.
type Identity struct {
	ProjectRoot  string    `json:"project_root"`
	Harness      string    `json:"harness"`
	Model        string    `json:"model,omitempty"`
	ExecutorPID  int       `json:"executor_pid"`
	ExecutorHost string    `json:"executor_host"`
	StartedAt    time.Time `json:"started_at"`
}

// Event mirrors a bead-event the worker would write to its local event log.
type Event struct {
	BeadID    string          `json:"bead_id"`
	AttemptID string          `json:"attempt_id"`
	Kind      string          `json:"kind"`
	Body      json.RawMessage `json:"body,omitempty"`
}

// Config tunes the probe cadence, jitter, backoff, and buffer capacity. Zero
// values mean "use the package default".
type Config struct {
	BaseInterval     time.Duration
	MaxInterval      time.Duration
	JitterPct        float64
	BackoffThreshold int
	BufferCap        int

	// AddrFunc returns the current server URL (scheme://host:port) or "" when
	// no server is registered. Default reads server.addr via the production
	// XDG path.
	AddrFunc func() string

	// HTTPClient is used for register/event/backfill POSTs. Default is a
	// short-timeout client.
	HTTPClient *http.Client

	// Now overrides time.Now (testing).
	Now func() time.Time

	// Rand overrides the jitter source (testing).
	Rand *rand.Rand

	// Logger receives best-effort failure messages (default: discarded).
	Logger io.Writer
}

func (c *Config) applyDefaults() {
	if c.BaseInterval == 0 {
		c.BaseInterval = DefaultBaseInterval
	}
	if c.MaxInterval == 0 {
		c.MaxInterval = DefaultMaxInterval
	}
	if c.JitterPct == 0 {
		c.JitterPct = DefaultJitterPct
	}
	if c.BackoffThreshold == 0 {
		c.BackoffThreshold = DefaultBackoffThreshold
	}
	if c.BufferCap == 0 {
		c.BufferCap = DefaultBufferCap
	}
	if c.HTTPClient == nil {
		c.HTTPClient = &http.Client{Timeout: 5 * time.Second}
	}
	if c.Now == nil {
		c.Now = time.Now
	}
	if c.Rand == nil {
		c.Rand = rand.New(rand.NewSource(time.Now().UnixNano()))
	}
	if c.Logger == nil {
		c.Logger = io.Discard
	}
}

// Probe is the worker-side server probe + event mirror. Constructed via New;
// driven by Start; events fed via RecordEvent. Stop releases the goroutine.
type Probe struct {
	ident Identity
	cfg   Config

	mu       sync.Mutex
	state    state
	workerID string

	// buf is the NotConnected ring buffer. Events emitted while Connected
	// bypass the buffer (POSTed inline best-effort).
	buf      []Event
	dropped  bool

	stopOnce sync.Once
	stopCh   chan struct{}
	doneCh   chan struct{}

	// Test hooks: when non-nil, called after each probe iteration.
	OnProbe func(connected bool, interval time.Duration)
}

type state int

const (
	stateNotConnected state = iota
	stateConnected
)

// New constructs a Probe with the given identity. Config is copied; nil
// fields are filled with package defaults.
func New(ident Identity, cfg Config) *Probe {
	cfg.applyDefaults()
	return &Probe{
		ident:  ident,
		cfg:    cfg,
		stopCh: make(chan struct{}),
		doneCh: make(chan struct{}),
		buf:    make([]Event, 0, cfg.BufferCap),
	}
}

// Start launches the probe goroutine. The first probe fires immediately
// (no initial sleep), per ADR-022 §Probe + freshness state model. The
// goroutine returns when ctx is canceled or Stop is called.
func (p *Probe) Start(ctx context.Context) {
	go p.run(ctx)
}

// Stop signals the goroutine to exit and waits for it.
func (p *Probe) Stop() {
	p.stopOnce.Do(func() { close(p.stopCh) })
	<-p.doneCh
}

// State reports whether the probe currently sees the server as reachable.
func (p *Probe) Connected() bool {
	p.mu.Lock()
	defer p.mu.Unlock()
	return p.state == stateConnected
}

// WorkerID returns the most recent worker_id issued by the server, or "" if
// the worker is not currently registered.
func (p *Probe) WorkerID() string {
	p.mu.Lock()
	defer p.mu.Unlock()
	return p.workerID
}

// HadDroppedBackfill reports whether the ring buffer has overflowed since
// the last successful backfill.
func (p *Probe) HadDroppedBackfill() bool {
	p.mu.Lock()
	defer p.mu.Unlock()
	return p.dropped
}

// BufferLen returns the current ring-buffer length (test/diagnostic).
func (p *Probe) BufferLen() int {
	p.mu.Lock()
	defer p.mu.Unlock()
	return len(p.buf)
}

// RecordEvent feeds a bead-event into the probe. If Connected, the event is
// POSTed to the server best-effort and not buffered. If NotConnected, the
// event lands in the ring buffer for backfill on next reconnect. Never
// blocks the caller on network I/O — POSTs are dispatched in a goroutine.
func (p *Probe) RecordEvent(ev Event) {
	p.mu.Lock()
	connected := p.state == stateConnected
	workerID := p.workerID
	addr := ""
	if connected && p.cfg.AddrFunc != nil {
		addr = p.cfg.AddrFunc()
	}
	if !connected || workerID == "" || addr == "" {
		p.appendBufferLocked(ev)
		p.mu.Unlock()
		return
	}
	p.mu.Unlock()
	go p.postEvent(addr, workerID, ev)
}

func (p *Probe) appendBufferLocked(ev Event) {
	if len(p.buf) >= p.cfg.BufferCap {
		// Drop oldest; record overflow.
		copy(p.buf, p.buf[1:])
		p.buf[len(p.buf)-1] = ev
		p.dropped = true
		return
	}
	p.buf = append(p.buf, ev)
}

func (p *Probe) run(ctx context.Context) {
	defer close(p.doneCh)

	// Immediate first probe (no initial sleep).
	p.tick(ctx)

	consecutiveFails := 0
	for {
		// Decide next interval: backoff after threshold consecutive failures,
		// otherwise jittered base.
		interval := p.cfg.BaseInterval
		if consecutiveFails >= p.cfg.BackoffThreshold {
			interval = p.cfg.MaxInterval
		}
		interval = applyJitter(interval, p.cfg.JitterPct, p.cfg.Rand)

		if p.OnProbe != nil {
			p.OnProbe(p.Connected(), interval)
		}

		t := time.NewTimer(interval)
		select {
		case <-ctx.Done():
			t.Stop()
			return
		case <-p.stopCh:
			t.Stop()
			return
		case <-t.C:
		}

		ok := p.tick(ctx)
		if ok {
			consecutiveFails = 0
		} else {
			consecutiveFails++
		}
	}
}

// tick performs one probe cycle and returns true on a successful reach
// (server replied to register or to a register that was already in place).
func (p *Probe) tick(ctx context.Context) bool {
	addr := ""
	if p.cfg.AddrFunc != nil {
		addr = p.cfg.AddrFunc()
	}
	if addr == "" {
		// No server configured. Drive Connected→NotConnected if we used to
		// be connected; otherwise no-op.
		p.markDisconnected("no_addr")
		return false
	}

	// Already connected: cheap reachability check by hitting register again
	// is overkill; we just trust the connection and let event POSTs surface
	// failures via the failure-counter (markDisconnected is called from
	// postEvent when the POST fails). This keeps probe traffic minimal.
	if p.Connected() {
		return true
	}

	// NotConnected: attempt to register.
	workerID, err := p.postRegister(ctx, addr)
	if err != nil {
		fmt.Fprintf(p.cfg.Logger, "workerprobe: register failed: %v\n", err)
		return false
	}
	p.markConnected(workerID)

	// Drain the ring buffer via backfill (best-effort).
	p.flushBackfill(ctx, addr, workerID)
	return true
}

func (p *Probe) markConnected(workerID string) {
	p.mu.Lock()
	p.state = stateConnected
	p.workerID = workerID
	p.mu.Unlock()
}

func (p *Probe) markDisconnected(reason string) {
	p.mu.Lock()
	if p.state == stateConnected {
		fmt.Fprintf(p.cfg.Logger, "workerprobe: disconnect (%s)\n", reason)
	}
	p.state = stateNotConnected
	p.workerID = ""
	p.mu.Unlock()
}

func (p *Probe) flushBackfill(ctx context.Context, addr, workerID string) {
	p.mu.Lock()
	if len(p.buf) == 0 && !p.dropped {
		p.mu.Unlock()
		return
	}
	events := make([]Event, len(p.buf))
	copy(events, p.buf)
	dropped := p.dropped
	p.mu.Unlock()

	if err := p.postBackfill(ctx, addr, workerID, events, dropped); err != nil {
		fmt.Fprintf(p.cfg.Logger, "workerprobe: backfill failed: %v\n", err)
		return
	}

	// Success: clear the ring buffer.
	p.mu.Lock()
	p.buf = p.buf[:0]
	p.dropped = false
	p.mu.Unlock()
}

// postRegister POSTs the identity envelope and returns the issued worker_id.
func (p *Probe) postRegister(ctx context.Context, addr string) (string, error) {
	body, err := json.Marshal(p.ident)
	if err != nil {
		return "", err
	}
	req, err := http.NewRequestWithContext(ctx, http.MethodPost, addr+"/api/workers/register", bytes.NewReader(body))
	if err != nil {
		return "", err
	}
	req.Header.Set("Content-Type", "application/json")
	resp, err := p.cfg.HTTPClient.Do(req)
	if err != nil {
		return "", err
	}
	defer resp.Body.Close()
	if resp.StatusCode != http.StatusOK {
		return "", fmt.Errorf("register: status=%d", resp.StatusCode)
	}
	var out struct {
		WorkerID string `json:"worker_id"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&out); err != nil {
		return "", err
	}
	if out.WorkerID == "" {
		return "", fmt.Errorf("register: empty worker_id")
	}
	return out.WorkerID, nil
}

// postEvent best-effort mirrors a single event. On failure, marks the probe
// NotConnected so the next probe tick re-registers (and the event re-enters
// the ring buffer the next time RecordEvent is called).
func (p *Probe) postEvent(addr, workerID string, ev Event) {
	body, err := json.Marshal(ev)
	if err != nil {
		fmt.Fprintf(p.cfg.Logger, "workerprobe: event marshal failed: %v\n", err)
		return
	}
	req, err := http.NewRequest(http.MethodPost, addr+"/api/workers/"+workerID+"/event", bytes.NewReader(body))
	if err != nil {
		fmt.Fprintf(p.cfg.Logger, "workerprobe: event request failed: %v\n", err)
		return
	}
	req.Header.Set("Content-Type", "application/json")
	resp, err := p.cfg.HTTPClient.Do(req)
	if err != nil {
		fmt.Fprintf(p.cfg.Logger, "workerprobe: event POST failed: %v\n", err)
		// Re-buffer the event so a future backfill catches it; flip state.
		p.mu.Lock()
		p.appendBufferLocked(ev)
		p.mu.Unlock()
		p.markDisconnected("event_post_error")
		return
	}
	defer resp.Body.Close()
	switch resp.StatusCode {
	case http.StatusNoContent:
		// Mirrored.
	case http.StatusGone:
		// Server forgot us (restarted between register and event). Mark
		// disconnected; next probe will re-register.
		p.mu.Lock()
		p.appendBufferLocked(ev)
		p.mu.Unlock()
		p.markDisconnected("event_unknown_worker")
	default:
		fmt.Fprintf(p.cfg.Logger, "workerprobe: event status=%d\n", resp.StatusCode)
		p.mu.Lock()
		p.appendBufferLocked(ev)
		p.mu.Unlock()
	}
}

// postBackfill replays the NotConnected ring buffer.
func (p *Probe) postBackfill(ctx context.Context, addr, workerID string, events []Event, dropped bool) error {
	body, err := json.Marshal(struct {
		Events  []Event `json:"events"`
		Dropped bool    `json:"dropped,omitempty"`
	}{Events: events, Dropped: dropped})
	if err != nil {
		return err
	}
	req, err := http.NewRequestWithContext(ctx, http.MethodPost, addr+"/api/workers/"+workerID+"/backfill", bytes.NewReader(body))
	if err != nil {
		return err
	}
	req.Header.Set("Content-Type", "application/json")
	resp, err := p.cfg.HTTPClient.Do(req)
	if err != nil {
		return err
	}
	defer resp.Body.Close()
	if resp.StatusCode != http.StatusNoContent {
		return fmt.Errorf("backfill: status=%d", resp.StatusCode)
	}
	return nil
}

// applyJitter returns base scaled by a uniform random factor in
// [1-pct, 1+pct]. pct is clamped to [0, 1).
func applyJitter(base time.Duration, pct float64, r *rand.Rand) time.Duration {
	if pct <= 0 {
		return base
	}
	if pct >= 1 {
		pct = 0.99
	}
	// Uniform in [-pct, +pct].
	delta := (r.Float64()*2 - 1) * pct
	scaled := time.Duration(float64(base) * (1 + delta))
	if scaled < time.Millisecond {
		scaled = time.Millisecond
	}
	return scaled
}

package workerprobe

import (
	"context"
	"encoding/json"
	"io"
	"math/rand"
	"net/http"
	"net/http/httptest"
	"sync"
	"sync/atomic"
	"testing"
	"time"
)

// fakeServer is a minimal stand-in for the worker-ingest endpoints. Tests
// drive Reachable to flip the server's "presence" without tearing down the
// httptest.Server.
type fakeServer struct {
	mu        sync.Mutex
	reachable bool
	workerID  string

	registered  int32
	events      int32
	backfills   int32
	lastEvents  []Event
	lastDropped bool
	failNextRegister bool
}

func newFakeServer(workerID string) *fakeServer {
	return &fakeServer{reachable: true, workerID: workerID}
}

func (f *fakeServer) Handler() http.Handler {
	mux := http.NewServeMux()
	mux.HandleFunc("/api/workers/register", func(w http.ResponseWriter, r *http.Request) {
		f.mu.Lock()
		if !f.reachable {
			f.mu.Unlock()
			http.Error(w, "down", http.StatusServiceUnavailable)
			return
		}
		if f.failNextRegister {
			f.failNextRegister = false
			f.mu.Unlock()
			http.Error(w, "fail", http.StatusInternalServerError)
			return
		}
		atomic.AddInt32(&f.registered, 1)
		id := f.workerID
		f.mu.Unlock()
		_ = json.NewEncoder(w).Encode(map[string]string{"worker_id": id})
	})
	mux.HandleFunc("/api/workers/", func(w http.ResponseWriter, r *http.Request) {
		f.mu.Lock()
		reachable := f.reachable
		f.mu.Unlock()
		if !reachable {
			http.Error(w, "down", http.StatusServiceUnavailable)
			return
		}
		// Expect /api/workers/{id}/event or /backfill
		switch {
		case hasSuffix(r.URL.Path, "/event"):
			var ev Event
			if err := json.NewDecoder(r.Body).Decode(&ev); err != nil {
				http.Error(w, err.Error(), http.StatusBadRequest)
				return
			}
			f.mu.Lock()
			f.lastEvents = append(f.lastEvents, ev)
			f.mu.Unlock()
			atomic.AddInt32(&f.events, 1)
			w.WriteHeader(http.StatusNoContent)
		case hasSuffix(r.URL.Path, "/backfill"):
			var req struct {
				Events  []Event `json:"events"`
				Dropped bool    `json:"dropped"`
			}
			if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
				http.Error(w, err.Error(), http.StatusBadRequest)
				return
			}
			f.mu.Lock()
			f.lastEvents = append(f.lastEvents, req.Events...)
			f.lastDropped = f.lastDropped || req.Dropped
			f.mu.Unlock()
			atomic.AddInt32(&f.backfills, 1)
			w.WriteHeader(http.StatusNoContent)
		default:
			http.NotFound(w, r)
		}
	})
	return mux
}

func hasSuffix(s, suf string) bool {
	return len(s) >= len(suf) && s[len(s)-len(suf):] == suf
}

// startFakeServer returns a running httptest.Server and a function to stop it.
func startFakeServer(t *testing.T, fs *fakeServer) *httptest.Server {
	t.Helper()
	ts := httptest.NewServer(fs.Handler())
	t.Cleanup(ts.Close)
	return ts
}

// newTestProbe constructs a Probe with short intervals + deterministic jitter,
// pointed at fs's URL via the supplied addrFunc.
func newTestProbe(addrFunc func() string) *Probe {
	return New(Identity{
		ProjectRoot:  "/tmp/probe-test",
		Harness:      "claude",
		ExecutorPID:  4242,
		ExecutorHost: "host.test",
		StartedAt:    time.Now().UTC(),
	}, Config{
		BaseInterval:     20 * time.Millisecond,
		MaxInterval:      200 * time.Millisecond,
		JitterPct:        0.20,
		BackoffThreshold: 5,
		BufferCap:        4,
		AddrFunc:         addrFunc,
		HTTPClient:       &http.Client{Timeout: 1 * time.Second},
		Rand:             rand.New(rand.NewSource(42)),
		Logger:           io.Discard,
	})
}

// TestWorker_ProbeImmediateFirst — the first probe must fire without waiting
// for BaseInterval, so registration with an already-running server happens
// promptly.
func TestWorker_ProbeImmediateFirst(t *testing.T) {
	fs := newFakeServer("wkr-imm")
	ts := startFakeServer(t, fs)

	p := newTestProbe(func() string { return ts.URL })
	// Set BaseInterval very long so we ONLY observe the immediate first probe.
	p.cfg.BaseInterval = 10 * time.Second
	p.cfg.MaxInterval = 10 * time.Second

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	p.Start(ctx)
	defer p.Stop()

	deadline := time.Now().Add(500 * time.Millisecond)
	for time.Now().Before(deadline) {
		if p.Connected() && p.WorkerID() == "wkr-imm" {
			return
		}
		time.Sleep(5 * time.Millisecond)
	}
	t.Fatalf("probe did not register immediately; connected=%v workerID=%q registered=%d",
		p.Connected(), p.WorkerID(), atomic.LoadInt32(&fs.registered))
}

// TestWorker_ProbeJitter — successive intervals must vary within ±JitterPct
// of BaseInterval (and stay positive). We sample 30 intervals and require
// that they span a non-trivial range (proves jitter is applied) and stay
// within the [1-pct, 1+pct] envelope.
func TestWorker_ProbeJitter(t *testing.T) {
	fs := newFakeServer("wkr-jit")
	ts := startFakeServer(t, fs)

	p := newTestProbe(func() string { return ts.URL })
	const base = 50 * time.Millisecond
	const pct = 0.20
	p.cfg.BaseInterval = base
	p.cfg.MaxInterval = base
	p.cfg.JitterPct = pct
	p.cfg.Rand = rand.New(rand.NewSource(7))

	const samples = 30
	intervals := make([]time.Duration, 0, samples)
	var mu sync.Mutex
	done := make(chan struct{})
	p.OnProbe = func(connected bool, interval time.Duration) {
		mu.Lock()
		if len(intervals) < samples {
			intervals = append(intervals, interval)
			if len(intervals) == samples {
				close(done)
			}
		}
		mu.Unlock()
	}

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	p.Start(ctx)
	defer p.Stop()

	select {
	case <-done:
	case <-time.After(10 * time.Second):
		t.Fatalf("did not collect %d intervals (got %d)", samples, len(intervals))
	}

	mu.Lock()
	defer mu.Unlock()
	min := intervals[0]
	max := intervals[0]
	low := time.Duration(float64(base) * (1 - pct))
	high := time.Duration(float64(base) * (1 + pct))
	for _, d := range intervals {
		if d < low || d > high {
			t.Errorf("interval %v out of envelope [%v,%v]", d, low, high)
		}
		if d < min {
			min = d
		}
		if d > max {
			max = d
		}
	}
	if max-min < base/10 {
		t.Errorf("intervals show ≤10%% variance (min=%v max=%v); jitter not applied", min, max)
	}
}

// TestWorker_BackfillOnReconnect — events recorded while NotConnected MUST
// be delivered via /backfill on the NotConnected→Connected transition.
func TestWorker_BackfillOnReconnect(t *testing.T) {
	fs := newFakeServer("wkr-bf")
	ts := startFakeServer(t, fs)

	// Start with the addr unreachable (AddrFunc returns "").
	var addr atomic.Value
	addr.Store("") // empty means no server
	addrFunc := func() string {
		if v := addr.Load(); v != nil {
			return v.(string)
		}
		return ""
	}
	p := newTestProbe(addrFunc)

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	p.Start(ctx)
	defer p.Stop()

	// Wait one probe cycle to ensure the goroutine ran the immediate first probe
	// in NotConnected state.
	time.Sleep(60 * time.Millisecond)
	if p.Connected() {
		t.Fatalf("probe should be NotConnected with empty addr")
	}

	// Record events while disconnected — they should buffer.
	p.RecordEvent(Event{BeadID: "ddx-aa", Kind: "attempt.started"})
	p.RecordEvent(Event{BeadID: "ddx-aa", Kind: "result"})
	if got := p.BufferLen(); got != 2 {
		t.Fatalf("buffer len after 2 disconnected events: got %d, want 2", got)
	}

	// Flip addr to point at the fake server.
	addr.Store(ts.URL)

	deadline := time.Now().Add(2 * time.Second)
	for time.Now().Before(deadline) {
		if atomic.LoadInt32(&fs.backfills) > 0 && p.BufferLen() == 0 {
			break
		}
		time.Sleep(10 * time.Millisecond)
	}
	if atomic.LoadInt32(&fs.backfills) == 0 {
		t.Fatalf("no backfill POST received")
	}
	if got := p.BufferLen(); got != 0 {
		t.Errorf("ring buffer not cleared after successful backfill; got len=%d", got)
	}
	fs.mu.Lock()
	got := len(fs.lastEvents)
	fs.mu.Unlock()
	if got != 2 {
		t.Errorf("server received %d events via backfill, want 2", got)
	}
}

// TestWorker_BackoffOnFailures — five consecutive probe failures MUST
// stretch the next interval to MaxInterval (backoff).
func TestWorker_BackoffOnFailures(t *testing.T) {
	// AddrFunc returns "" forever => every probe tick fails.
	p := newTestProbe(func() string { return "" })
	p.cfg.BaseInterval = 10 * time.Millisecond
	p.cfg.MaxInterval = 200 * time.Millisecond
	p.cfg.JitterPct = 0 // deterministic
	p.cfg.BackoffThreshold = 5

	var seen []time.Duration
	var mu sync.Mutex
	want := 7 // first 5 = base, then 2 = max
	done := make(chan struct{})
	p.OnProbe = func(connected bool, interval time.Duration) {
		mu.Lock()
		if len(seen) < want {
			seen = append(seen, interval)
			if len(seen) == want {
				close(done)
			}
		}
		mu.Unlock()
	}

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	p.Start(ctx)
	defer p.Stop()

	select {
	case <-done:
	case <-time.After(5 * time.Second):
		t.Fatalf("did not collect %d intervals (got %d)", want, len(seen))
	}

	mu.Lock()
	defer mu.Unlock()
	for i, d := range seen {
		if i < 5 {
			if d != 10*time.Millisecond {
				t.Errorf("interval[%d]=%v, want base=10ms", i, d)
			}
		} else {
			if d != 200*time.Millisecond {
				t.Errorf("interval[%d]=%v, want max=200ms (backoff)", i, d)
			}
		}
	}
}

// TestWorker_NoServer_StillWorks — RecordEvent never panics, never blocks,
// the probe goroutine starts/stops cleanly when no server is reachable, and
// events accumulate in the ring buffer up to BufferCap.
func TestWorker_NoServer_StillWorks(t *testing.T) {
	p := newTestProbe(func() string { return "" })

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	p.Start(ctx)
	defer p.Stop()

	// Record more events than BufferCap to exercise overflow.
	for i := 0; i < p.cfg.BufferCap+3; i++ {
		p.RecordEvent(Event{
			BeadID: "ddx-overflow",
			Kind:   "attempt.started",
		})
	}

	if got := p.BufferLen(); got != p.cfg.BufferCap {
		t.Errorf("buffer len: got %d, want %d (BufferCap)", got, p.cfg.BufferCap)
	}
	if !p.HadDroppedBackfill() {
		t.Error("HadDroppedBackfill should be true after overflow")
	}
	if p.Connected() {
		t.Error("probe should remain NotConnected without a server")
	}
	if p.WorkerID() != "" {
		t.Errorf("WorkerID should be empty when not registered; got %q", p.WorkerID())
	}
}

